export async function chartEarnedValue(request: NextRequest, projectId: string) {
  const auth = authenticateRequest(request);
  if (!auth.user) return auth.errorResponse;
  const id = parseInt(projectId); // ... (validasi & error handling)

  try {
    const projectResult = await query<{ start_date: Date; end_date: Date; status: string }>('SELECT start_date, end_date, status FROM tb_proyek WHERE id = $1', [id]);
    if (projectResult.rowCount === 0) return NextResponse.json({ success: false, error: 'Project not found' }, { status: 404 });
    const project = projectResult.rows[0];
    const startDate = new Date(project.start_date), endDate = new Date(project.end_date), today = new Date();
    const totalTasksResult = await query<{ total: string }>('SELECT COUNT(*)::int AS total FROM tb_tugas WHERE project_id = $1', [id]);
    const totalTasks = parseInt(String(totalTasksResult.rows[0].total)) || 0;
    const timeline: Array<{ date: string; pv: number; ev: number; spi: number }> = [];
    let current = new Date(startDate);

    const getEV = async (date: Date): Promise<number> => {
      if (totalTasks === 0) {
        const reportResult = await query<{ progress_percentage: string }>('SELECT progress_percentage FROM daily_reports WHERE project_id = $1 AND report_date <= $2 ORDER BY report_date DESC, created_at DESC LIMIT 1', [id, date.toISOString().split('T')[0]]);
        return reportResult.rowCount && reportResult.rowCount > 0 ? parseFloat(reportResult.rows[0].progress_percentage) : 0;
      } else {
        const completedResult = await query<{ completed: string }>('SELECT COUNT(*) FILTER (WHERE status = \'done\' AND updated_at <= $2)::int AS completed FROM tb_tugas WHERE project_id = $1', [id, date.toISOString()]);
        return totalTasks > 0 ? (parseInt(String(completedResult.rows[0].completed)) / totalTasks) * 100 : 0;
      }
    };

    while (current <= (today < endDate ? today : endDate)) {
      const pv = calculatePlannedValue(startDate, endDate, current);
      const ev = await getEV(current);
      const spi = pv > 0 ? Math.round((ev / pv) * 10000) / 10000 : 1;
      timeline.push({ date: current.toISOString().split('T')[0], pv: Math.round(pv * 100) / 100, ev: Math.round(ev * 100) / 100, spi });
      current = new Date(current.getTime() + 7 * 24 * 60 * 60 * 1000);
    }
    // ... (helper omitted)
    return NextResponse.json({ success: true, data: { project_id: id, total_tasks: totalTasks, timeline } });
  } catch (err) {
    // ... (validasi & error handling)
  }
}
